            v[2] = v[2] * v[12] + v[5] * v[13];
            v[14] = 5.55111512312578e-17 * v[9] + v[10];
            v[15] = v[8] * v[11] + v[2] * v[9] + v[5] * v[14];
            v[16] = v[8] + -4.89658313895802e-12 * v[2] + 4.89663865010925e-12 * v[5];
            y[36] = y[24] + 0.102 * v[8];
